def factorial(n: int) -> int:
    cache = {0: 1}
    def calculate_factorial(x):
        if x not in cache:
            cache[x] = x * calculate_factorial(x - 1)
        return cache[x]
    return calculate_factorial(n)

def factorial(n: int) -> int:
    if n <= 1:
        return 1
